INSERT INTO word_families (id, pattern, sound, rule) VALUES
  ('f1000000-0000-4000-8000-000000000101', '-eal', '/iːl/', 'The ea vowel team often says long E, as in deal and meal.'),
  ('f1000000-0000-4000-8000-000000000102', '-et', '/ɛt/', 'Short e followed by t keeps a crisp /ɛ/ vowel, as in get and pet.'),
  ('f1000000-0000-4000-8000-000000000103', '-ap', '/æp/', 'Short a followed by p, as in cap and nap.'),
  ('f1000000-0000-4000-8000-000000000104', '-at', '/æt/', 'Short a followed by t, as in cat and bat.'),
  ('f1000000-0000-4000-8000-000000000105', '-an', '/æn/', 'Short a followed by n, as in man and can.'),
  ('f1000000-0000-4000-8000-000000000106', '-ell', '/ɛl/', 'The -ell ending keeps a short e sound, as in bell and sell.'),
  ('f1000000-0000-4000-8000-000000000107', '-ock', '/ɒk/', 'Short o followed by ck, as in lock and rock.'),
  ('f1000000-0000-4000-8000-000000000108', '-ug', '/ʌg/', 'Short u followed by g, as in bug and rug.'),
  ('f1000000-0000-4000-8000-000000000109', '-un', '/ʌn/', 'Short u followed by n, as in fun and run.'),
  ('f1000000-0000-4000-8000-000000000110', '-op', '/ɒp/', 'Short o followed by p, as in top and hop.')
ON CONFLICT (id) DO NOTHING;

